11	const contextMiddleware = async (req, res, next) => {
12	    const token = req.headers.authorization;
13	    let user = null;
14	    if (token) {
15	        user = await getUserInfo(token);
16	    }
17	    
18	    const context = {
19	        user: user,
20	        reqId: uuidv4()
21	    };
22	
23	    asyncLocalStorage.run(context, next);
24	};
25	
26	module.exports = {
27	    getContext,
28	    contextMiddleware,
