1022	// ─── Item Type Search Helpers ────────────────────────────────────────────────
1023	
1024	exports.normalizeSearchTerm = (value = '') =>
1025	  value.toLowerCase().trim().replace(/\s+/g, ' ');
1026	
1027	exports.getItemTypeSearchTerms = (query = '') => {
1028	  const normalized = exports.normalizeSearchTerm(query);
1029	  const tokens = normalized.split(/\s+/).filter(Boolean);
1030	  return Array.from(new Set([normalized, ...tokens].filter(Boolean)));
1031	};
1032	
1033	/**
1034	 * Levenshtein edit distance between two strings.
1035	 * Lower = more similar. Used for fuzzy/typo-tolerant matching.
1036	 */
1037	const levenshteinDistance = (a, b) => {
1038	  const m = a.length;
1039	  const n = b.length;
1040	  const dp = Array.from({ length: m + 1 }, (_, i) =>
1041	    Array.from({ length: n + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0))
1042	  );
1043	  for (let i = 1; i <= m; i++) {
1044	    for (let j = 1; j <= n; j++) {
1045	      dp[i][j] = a[i - 1] === b[j - 1]
1046	        ? dp[i - 1][j - 1]
1047	        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
1048	    }
1049	  }
1050	  return dp[m][n];
1051	};
1052	
1053	/**
1054	 * Returns a 0–1 similarity ratio based on edit distance.
1055	 */
1056	const stringSimilarity = (a, b) => {
1057	  if (!a || !b) return 0;
1058	  const maxLen = Math.max(a.length, b.length);
1059	  return maxLen === 0 ? 1 : 1 - levenshteinDistance(a, b) / maxLen;
1060	};
1061	
1062	/**
1063	 * Scores a DB candidate against the search query.
1064	 * Combines exact/prefix/contains rules with fuzzy similarity so
1065	 * near-matches and slight misspellings still rank well.
1066	 */
1067	exports.scoreItemTypeCandidate = (candidate, query) => {
1068	  const normalizedQuery = exports.normalizeSearchTerm(query);
1069	  const candidateName = exports.normalizeSearchTerm(candidate?.item_type_name || '');
1070	  const candidateDescription = exports.normalizeSearchTerm(candidate?.item_type_description || '');
1071	  const queryTerms = exports.getItemTypeSearchTerms(query);
1072	
1073	  if (!normalizedQuery) return 0;
1074	
1075	  let score = 0;
1076	
1077	  // Exact / prefix / substring matches on full query
1078	  if (candidateName === normalizedQuery) score += 120;
1079	  if (candidateName.startsWith(normalizedQuery)) score += 80;
1080	  if (candidateName.includes(normalizedQuery)) score += 50;
1081	  if (candidateDescription.includes(normalizedQuery)) score += 25;
1082	
1083	  // Token-level substring matches
1084	  queryTerms.forEach((term) => {
1085	    if (candidateName.startsWith(term)) score += 18;
1086	    if (candidateName.includes(term)) score += 10;
1087	    if (candidateDescription.includes(term)) score += 6;
1088	  });
1089	
1090	  // Fuzzy similarity — catches typos and near-matches
1091	  const nameSimilarity = stringSimilarity(candidateName, normalizedQuery);
1092	  score += Math.round(nameSimilarity * 40);
1093	
1094	  // Also score each query token against each word in the candidate name
1095	  const nameWords = candidateName.split(/\s+/).filter(Boolean);
1096	  queryTerms.forEach((term) => {
1097	    const bestWordSimilarity = Math.max(
1098	      0,
1099	      ...nameWords.map((word) => stringSimilarity(word, term))
1100	    );
1101	    if (bestWordSimilarity >= 0.75) {
1102	      score += Math.round(bestWordSimilarity * 20);
1103	    }
1104	  });
1105	
1106	  return score;
1107	};
