106	        const raw = typeof filterDef.filter === 'string' ? filterDef.filter : String(filterDef.filter || '');
107	        const terms = raw.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
108	        if (terms.length > 0) {
109	          terms.forEach(term => {
110	            tagsConditions.push({
111	              [Op.or]: [
112	                { tags: { [Op.iLike]: `%${term}%` } },
113	                { item_descr_name: { [Op.iLike]: `%${term}%` } }
114	              ]
115	            });
116	          });
117	        }
118	        return; // handled
119	      }
120	
121	      const condition = buildCondition(filterDef, dbField);
122	      if (!condition) return;
123	
124	      // Route to correct merch group or itemHeader
125	      const match = dbField.match(/^merchGroup0([1-6])/);
126	      if (match) {
127	        const key = `merchGroup0${match[1]}`;
128	        merchGroupFilters[key] = condition;
129	      } else {
130	        whereClause[dbField] = condition;
131	      }
132	    });
133	
134	    // 🔹 Combine division codes and tags conditions properly (AND them together)
135	    const andConditions = [];
136	    const divisionCodeIds = req.query.divisionCodeIds ? JSON.parse(req.query.divisionCodeIds) : [];
137	    if (divisionCodeIds.length > 0) {
138	      divisionCodeIds.push(2);
139	      andConditions.push({
