144	      });
145	    }
146	
147	    if (tagsConditions.length > 0) {
148	      andConditions.push({
149	        [Op.or]: tagsConditions
150	      });
151	    }
152	
153	    if (andConditions.length > 0) {
154	      whereClause[Op.and] = andConditions;
155	    }
156	
157	    // 🔹 Helper: Generate merchGroup includes
158	    const generateMerchGroupIncludes = () => {
159	      return Object.entries(merchGroupFilters).map(([key, filter]) => {
160	        const match = key.match(/^merchGroup0([1-6])/);
161	        const hasFilter = Reflect.ownKeys(filter).length > 0;
162	        return {
163	          model: sql.merchGroup,
164	          as: key,
165	          required: hasFilter,
166	          where: hasFilter ? { mgTypeCode: `0${match[1]}`, mg_desc: filter, divisionCode_id_fk: divisionCodeIds } : undefined
167	        }
168	    }
169	    );
170	    };
171	
172	    const merchIncludes = generateMerchGroupIncludes();
173	
174	    // 🔹 Query 1: Accurate Count
175	    const count = await sql.itemHeader.count({
176	      where: whereClause,
177	      include: merchIncludes,
