16	ArtPiece.getAllitems = async (req, result) => {
17	  const { startRow, endRow, filterModel, tags = '' } = req.query;
18	  const limit = endRow - startRow;
19	  const offset = Number(startRow);
20	
21	  try {
22	    const filters = filterModel ? JSON.parse(filterModel) : {};
23	
24	    // 🔹 Normalize multi filters
25	    Object.keys(filters).forEach(field => {
26	      if (filters[field]?.filterType === 'multi') {
27	        const validSubFilter = filters[field].filterModels.find(sub => sub);
28	        filters[field] = validSubFilter || null;
29	      }
30	    });
31	
32	    // 🔹 Utility: Build Sequelize condition
33	    const buildCondition = (filterDef) => {
34	      switch (filterDef.type) {
35	        case 'contains': return { [Op.iLike]: `%${filterDef.filter}%` };
36	        case 'notContains': return { [Op.notILike]: `%${filterDef.filter}%` };
37	        case 'equals': return { [Op.eq]: filterDef.filter };
38	        case 'notEqual': return { [Op.ne]: filterDef.filter };
39	        case 'startsWith': return { [Op.iLike]: `${filterDef.filter}%` };
40	        case 'endsWith': return { [Op.iLike]: `%${filterDef.filter}` };
41	        default: return null;
42	      }
43	    };
44	
45	    // 🔹 Base where — archive view shows inactive, main view shows active
46	    const isArchive = req.query.isArchive === 'true';
47	    const mainWhere = { is_active: isArchive ? 'false' : 'true' };
48	
49	    // 🔹 Include all associations dynamically
50	    const associationAliases = ['licensor', 'property', 'style_guide', 'big_theme', 'little_theme', 'art_source', 'season', 'art_type', 'artist', 'age_group'];
51	    const include = [
52	      { model: sql.artPieceAttachment, as: 'artPieceAttachments', required: false },
53	      ...associationAliases.map(alias => {
54	        const mapping = mapFieldToColumn(alias);
55	        const model = mapping.table === 'artPiece' ? null : sql[mapping.table];
56	        return model ? { model, as: alias, required: false, where: {} } : null;
57	      }).filter(Boolean)
58	    ];
59	
60	    // 🔹 Map filters to main table or associations
61	    Object.entries(filters).forEach(([field, filterDef]) => {
62	      if (!filterDef?.filter) return;
63	
64	      const mapping = mapFieldToColumn(field); // { table, alias, column }
65	      // Special handling: tags filter should also search art_description
66	      if (mapping === 'tags' || mapping.column === 'tags') {
67	        const raw = typeof filterDef.filter === 'string' ? filterDef.filter : '';
68	        const terms = raw.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
69	        if (terms.length > 0) {
70	          mainWhere[Op.or] = mainWhere[Op.or] || [];
71	          terms.forEach(term => {
72	            mainWhere[Op.or].push({
73	              [Op.or]: [
74	                { tags: { [Op.iLike]: `%${term}%` } },
75	                { art_description: { [Op.iLike]: `%${term}%` } }
76	              ]
77	            });
78	          });
79	        }
80	        return; // handled
81	      }
82	      const condition = buildCondition(filterDef);
83	      if (!condition) return;
84	
85	      if (mapping.table === 'artPiece') {
86	        mainWhere[mapping.column] = condition;
87	      } else {
88	        let assoc = include.find(i => i.as === mapping.alias);
89	        if (!assoc) {
90	          assoc = { model: sql[mapping.table], as: mapping.alias, where: {}, required: true };
91	          include.push(assoc);
92	        }
93	        assoc.required = true;  // inner join because we have filter
94	        assoc.where[mapping.column] = condition;
95	      }
96	    });
97	
98	    // 🔹 Count query
99	    const count = await sql.artPiece.count({
100	      where: mainWhere,
101	      distinct: true,
102	      col: 'id',
103	      include
104	    });
105	
106	    // 🔹 Paginated data query
107	    const rows = await sql.artPiece.findAll({
108	      logging: console.log,
109	      attributes: [
110	        'id', 'art_description', 'licensor_id', 'property_id',
111	        'style_guide_id', 'big_theme_id', 'little_theme_id',
112	        'art_type_id', 'art_source_id', 'artist_id',
113	        'season_code_id', 'age_group_id', 'divisioncode_id', 'is_active',
114	        'tags', 'art_number'
115	      ],
116	      where: mainWhere,
117	      include,
118	      order: [
119	        ['id', 'DESC'],
120	        [{ model: sql.artPieceAttachment, as: 'artPieceAttachments' }, 'id', 'DESC']
121	      ],
122	      limit,
123	      offset
124	    });
125	
126	    const colHeaders = await getGridHeader(['artPiece']);
127	    const remappedData = await mapArtPiece(colHeaders, rows);
128	
129	    result(null, { rows: remappedData, totalCount: count });
130	
131	  } catch (err) {
132	    console.error('Error in ArtPiece.getAllitems:', err);
133	    result(null, err);
134	  }
