535	/** Human-readable labels for linked items (grid "Item Num" often maps to item_num_id; fall back when null). */
536	function linkedItemDisplayLabels(linkedItems) {
537	  const labels = [];
538	  const seen = new Set();
539	  for (const r of linkedItems) {
540	    const num = r.item_num_id != null ? String(r.item_num_id).trim() : '';
541	    const ref = r.ref_num != null ? String(r.ref_num).trim() : '';
542	    const dsn = r.dsn_ref_num != null ? String(r.dsn_ref_num).trim() : '';
543	    const pk = r.item_id_pk != null ? String(r.item_id_pk) : '';
544	    const label = num || ref || dsn || (pk ? `Item #${pk}` : '');
545	    if (label !== '' && !seen.has(label)) {
546	      seen.add(label);
547	      labels.push(label);
548	    }
549	  }
550	  return labels.sort((a, b) => a.localeCompare(b, undefined, { numeric: true }));
551	}
