25	function normalizeAssignments(input) {
26	  const rawAssignments = Array.isArray(input)
27	    ? input
28	    : Object.entries(input || {}).map(([role, value]) => ({
29	        role,
30	        userId: typeof value === 'object' && value !== null
31	          ? value.userId ?? value.user_id_fk
32	          : value,
33	      }));
34	
35	  return rawAssignments.map((assignment) => {
36	    const role = String(assignment.role || '').trim();
37	    if (!ROLE_SET.has(role)) {
38	      throw makeError(`Invalid product assignment role: ${role}`);
39	    }
40	
41	    return {
42	      role,
43	      userId: toInteger(assignment.userId ?? assignment.user_id_fk),
44	    };
45	  });
46	}
