83	ProductAssignmentService.setAssignments = async (itemId, assignments, actorUserId = null) => {
84	  const normalizedItemId = toInteger(itemId);
85	  if (!normalizedItemId) {
86	    throw makeError('A valid item id is required.');
87	  }
88	
89	  await assertItemExists(normalizedItemId);
90	  const normalizedAssignments = normalizeAssignments(assignments);
91	  const actorId = toInteger(actorUserId);
92	
93	  for (const assignment of normalizedAssignments) {
94	    if (!assignment.userId) {
95	      await sql.productUserAssignment.destroy({
96	        where: {
97	          item_id_fk: normalizedItemId,
98	          role: assignment.role,
99	        },
100	      });
101	      continue;
102	    }
103	
104	    await assertUserExists(assignment.userId);
105	
106	    const existing = await sql.productUserAssignment.findOne({
107	      where: {
108	        item_id_fk: normalizedItemId,
109	        role: assignment.role,
110	      },
111	    });
112	
113	    const now = new Date();
114	    if (existing) {
115	      await existing.update({
116	        user_id_fk: assignment.userId,
117	        updated_by_fk: actorId,
118	        updated_date: now,
119	      });
120	    } else {
121	      await sql.productUserAssignment.create({
122	        item_id_fk: normalizedItemId,
123	        role: assignment.role,
124	        user_id_fk: assignment.userId,
125	        created_by_fk: actorId,
126	        created_date: now,
127	        updated_by_fk: actorId,
128	        updated_date: now,
129	      });
130	    }
131	  }
132	
133	  return ProductAssignmentService.getAssignments(normalizedItemId);
