85	
86	        // create (or reuse) a 1:1 conversation with the user.
87	        try {
88	            const creds = new MicrosoftAppCredentials(appId, appPassword, channelAuthTenant);
89	            const connector = new ConnectorClient(creds, { baseUri: serviceUrl });
90	
91	            const params = {
92	                bot: { id: appId },
93	                members: [{ id: aadObjectId }],
94	                isGroup: false,
95	                channelData: {
96	                    tenant: { id: this.tenantId }
97	                }
98	            };
99	
100	            const created = await connector.conversations.createConversation(params);
101	            const conversationId = created?.id;
102	            if (!conversationId) return null;
103	
104	            const conv = { conversationId, serviceUrl };
105	            this._conversationByEmail.set(userEmail, conv);
106	            return conv;
107	        } catch (error) {
108	            console.warn(
109	                `Could not create bot conversation for ${userEmail}:`,
110	                error?.statusCode || error?.code,
111	                error?.message || String(error)
112	            );
113	            return null;
114	        }
115	    }
116	
117	    /**
118	     * Send a Bot Framework message to a Teams conversationId.
119	     */
120	    async sendBotMessageToConversationId(conversationId, userEmail, { text, summary, attachments } = {}, { serviceUrl } = {}) {
121	        if (!conversationId) {
122	            console.error("Missing conversationId for bot send.");
123	            return { ok: false, error: "Missing conversationId" };
124	        }
125	
126	        const { appId, appPassword, channelAuthTenant, serviceUrl: defaultServiceUrl } =
127	            this.getBotCredentialsConfig();
128	
129	        if (!appId || !appPassword) {
130	            console.error(
131	                "Missing bot credentials. Set MICROSOFT_APP_ID and MICROSOFT_APP_PASSWORD (or TEAMS_BOT_APP_ID/TEAMS_BOT_PASSWORD)."
132	            );
133	            return { ok: false, error: "Missing bot credentials" };
134	        }
135	
136	        const baseUri = serviceUrl || defaultServiceUrl;
137	
138	        const activity = {
139	            type: "message",
140	            text: text || "",
141	            summary: summary,
142	            attachments: Array.isArray(attachments) ? attachments : undefined
143	        };
144	
145	        try {
146	            const creds = new MicrosoftAppCredentials(appId, appPassword, channelAuthTenant);
147	            // For proactive sends we must provide the Bot Framework serviceUrl (region endpoint).
148	            const connector = new ConnectorClient(creds, { baseUri });
149	            await connector.conversations.sendToConversation(conversationId, activity);
150	            console.log(`Bot message sent to ${userEmail} via ${baseUri}`);
151	            return { ok: true, serviceUrl: baseUri };
152	        } catch (err) {
153	            const status = err?.statusCode || err?.code;
154	            const message = err?.message || String(err);
155	            console.warn(`Bot send failed for serviceUrl ${baseUri}:`, status, message);
156	            return {
157	                ok: false,
158	                error: err?.message || "Bot send failed",
159	                statusCode: err?.statusCode,
160	                details: err?.body
161	            };
162	        }
163	    }
164	
165	    async sendBotMessageToUserEmail(userEmail, { title, message, webUrl, attachments, summary, text } = {}) {
166	        const conv = await this.getOrCreateBotConversationForUserEmail(userEmail);
167	        if (!conv?.conversationId) {
168	            console.warn(`No conversationId found for ${userEmail}.`);
169	            return { ok: false, error: "conversationId_not_found" };
170	        }
171	
172	        const hasAttachments = Array.isArray(attachments) && attachments.length > 0;
173	        const fallbackText =
174	            text ||
175	            [
176	                title ? `**${title}**` : null,
177	                message || null,
178	                webUrl ? `[Open item](${webUrl})` : null
179	            ]
180	                .filter(Boolean)
181	                .join("\n\n");
182	
183	        // IMPORTANT: If we include both `text` and an Adaptive Card attachment, Teams renders the
184	        // text above the card (often perceived as a duplicate message). For card sends, omit text.
185	        const effectiveText = hasAttachments ? "" : fallbackText;
186	        const sendRes = await this.sendBotMessageToConversationId(
187	            conv.conversationId,
188	            userEmail,
189	            { text: effectiveText, summary, attachments },
190	            { serviceUrl: conv.serviceUrl }
191	        );
192	        return sendRes;
193	    }
